import boto3
from botocore.exceptions import NoCredentialsError
from PIL import Image
from io import BytesIO
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
import os

# AWS S3 credentials
AWS_ACCESS_KEY_ID = 'YOUR_AWS_ACCESS_KEY_ID'
AWS_SECRET_ACCESS_KEY = 'YOUR_AWS_SECRET_ACCESS_KEY'

# Set up S3 client
s3 = boto3.client('s3', aws_access_key_id=AWS_ACCESS_KEY_ID,
                      aws_secret_access_key=AWS_SECRET_ACCESS_KEY)

def generate_screenshot(url):
    try:
        # Set up Chrome options for headless mode
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        chrome_options.add_argument('--disable-gpu')

        # Create a new instance of the Chrome driver
        driver = webdriver.Chrome(options=chrome_options)

        # Navigate to the URL and take a screenshot
        driver.get(url)
        screenshot = driver.get_screenshot_as_png()

        # Close the browser window
        driver.quit()

        # Save the screenshot to S3
        s3.put_object(Body=screenshot, Bucket='your-bucket-name', Key=f'screenshots/{url}.png')

        return f'https://s3.amazonaws.com/your-bucket-name/screenshots/{url}.png'

    except NoCredentialsError:
        print("No AWS credentials found.")
        return None
    except Exception as e:
        print(f"An error occurred: {e}")
        return None

def validate_url(url):
    try:
        # Check if the URL is valid
        result = urlparse(url)
        if all([result.scheme, result.netloc]):
            return True
        else:
            return False
    except ValueError:
        return False

def main():
    url = input("Enter a URL to screenshot: ")
    if validate_url(url):
        screenshot_url = generate_screenshot(url)
        print(screenshot_url)
    else:
        print("Invalid URL")

if __name__ == "__main__":
    main()